def count_sessions(events, gap):
    from collections import defaultdict
    times = defaultdict(list)
    for u, t in events:
        times[u].append(t)
    total = 0
    for ts in times.values():
        ts.sort()
        total += 1 + sum(1 for a, b in zip(ts, ts[1:]) if b - a > gap)
    return total
